import { useState } from "react";
import { submitEventBooking } from "../utils/eventBookingApi";

const EventBooking = () => {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [phone, setPhone] = useState("");
  const [event_date, setEvent_date] = useState("");
  const [event_type, setEvent_type] = useState("");
  const [guests, setGuests] = useState("");

  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState("");
  const [error, setError] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");
    setSuccess("");

    try {
      const payload = {
        name,
        email,
        phone,
        event_date,
        event_type,
        guests: Number(guests) || 0,
        message: `${event_type} booking request for ${guests} guest(s).`,
      };

      const response = await submitEventBooking(payload);

      setLoading(false);
      setSuccess(response.data.message || "Event request sent successfully.");

      // reset fields
      setName("");
      setEmail("");
      setPhone("");
      setEvent_date("");
      setEvent_type("");
      setGuests("");

    } catch (err) {
      setLoading(false);
      setError(err.response?.data?.message || "Failed to send booking request");
      console.error(err);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <input
        name="name"
        placeholder="Name"
        value={name}
        onChange={(e) => setName(e.target.value)}
        required
      />

      <input
        name="email"
        placeholder="Email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        required
      />

      <input
        name="phone"
        placeholder="Phone"
        value={phone}
        onChange={(e) => setPhone(e.target.value)}
        required
      />

      <input
        type="date"
        name="event_date"
        value={event_date}
        onChange={(e) => setEvent_date(e.target.value)}
        required
      />

      <input
        name="event_type"
        placeholder="Event Type"
        value={event_type}
        onChange={(e) => setEvent_type(e.target.value)}
        required
      />

      <input
        type="number"
        name="guests"
        placeholder="Guests"
        value={guests}
        onChange={(e) => setGuests(e.target.value)}
        required
      />

      <button type="submit">
        {loading ? "Sending..." : "Send Event Request"}
      </button>

      {success && <p style={{ color: "green" }}>{success}</p>}
      {error && <p style={{ color: "red" }}>{error}</p>}
    </form>
  );
};

export default EventBooking;
